def convert_from_spm(cls, vocab=None, **kwargs):
        bos_token = str(kwargs.get("bos_token", "<s>"))
        pad_token = str(kwargs.get("pad_token", "<pad>"))
        eos_token = str(kwargs.get("eos_token", "</s>"))
        unk_token = str(kwargs.get("unk_token", "<unk>"))

        reordered_vocab = {
            bos_token: 0,
            pad_token: 1,
            eos_token: 2,
            unk_token: 3,
        }
        if vocab is not None:
            tokens = vocab.keys() if isinstance(vocab, dict) else [tok for tok, _ in vocab]
            for token in tokens:
                if token in reordered_vocab:
                    continue
                reordered_vocab[token] = len(reordered_vocab)
        kwargs["vocab"] = reordered_vocab
        return kwargs

@classmethod fn:convert_from_spm(vocab=None, **kwargs) = {
  bos_token = kwargs.get("bos_token","<s>")
  pad_token = kwargs.get("pad_token","<pad>")
  eos_token = kwargs.get("eos_token","</s>")
  unk_token = kwargs.get("unk_token","<unk>")
  vocab = {bos_token:0, pad_token:1, eos_token:2, unk_token:3} | 
           {t: len(vocab)+1 for t in (vocab.keys() if isinstance(vocab,dict) else [tok for tok,_ in vocab]) if t not in vocab}
  kwargs.update(vocab=vocab)
  return kwargs
}
